{"content":"1: using System;
2: using System.Linq;
3: using System.Reflection;
4: using System.Collections;
5: using System.Collections.Generic;
6: 
7: namespace DotNetKoans.Engine
8: {
9:     public abstract class Path : IEnumerable<Type>
10:     {
11:         internal Type[] Types;
12: 
13:         public int Walk(Sensei sensei)
14:         {
15:             try
16:             {
17:                 ForEachStep(step =>
18:                 {
19:                     sensei.Observe(step.Meditate());
20:                 });
21:             }
22:             catch (SenseiException e)
23:             { }
24: 
25:             sensei.Instruct(this);
26: 
27:             return sensei.Failed() ? -1 : 0;
28:         }
29: 
30:         public void ForEachKoan(Action<TypeInfo> action)
31:         {
32:             foreach (var type in this)
33:             {
34:                 action(type.GetTypeInfo());
35:             }
36:         }
37: 
38:         public void ForEachStep(Action<Step> action)
39:         {
40:             ForEachKoan(typeInfo =>
41:             {
42:                 var methods = typeInfo.GetMethods()
43:                 .Where(m => m.GetCustomAttributes(typeof(StepAttribute), false).Any())
44:                 .OrderBy(m => m.GetCustomAttributes(typeof(StepAttribute), false)
45:                                 .Cast<StepAttribute>().Single().Position)
46:                 .ToArray();
47: 
48:                 foreach (var methodInfo in methods)
49:                 {
50:                     action(new Step(typeInfo, methodInfo));
51:                 }
52:             });
53: 
54: 
55:         }
56: 
57:         IEnumerator IEnumerable.GetEnumerator()
58:         {
59:             return ((IEnumerable<Type>)Types).GetEnumerator();
60:         }
61: 
62:         IEnumerator<Type> IEnumerable<Type>.GetEnumerator()
63:         {
64:             return ((IEnumerable<Type>)Types).GetEnumerator();
65:         }
66:     }
67: }","url":"https://sourcegraph.sourcegraph.com/github.com/sg-benchmarks/DotNetKoans--dibench@dfc61171effb00d16ea1e4bd7bd44e2eced84484/-/blob/Engine/Path.cs"}

